frame_eqs:
wave_a = 0;
beat = if(bass > 1.9, 1, 0);
randr = if(beat, rand(1), randr);
randg = if(beat, rand(1), randg);
randb = if(beat, rand(1), randb);
lanerand = if(beat, 1+rand(49), lanerand);
modes = if(beat, int(rand(2)), modes);
modbeat1 = if(beat, 2+int(rand(14)), modbeat1);
modbeat2 = if(beat, 2+int(rand(14)), modbeat2);
modbeat3 = if(beat, 2+int(rand(14)), modbeat3);

q1 = beat;
q2 = randr; q3 = randg; q4 = randb;
q5 = lanerand; q6 = modes;
q7 = modbeat1; q8 = modbeat2; q9 = modbeat3;

wave_0_per_point:
y = 1-sample;
x -= .5;

tt = if (q6, (x+.5)*q5, (y+.5)*q5);
//r = if (above(tt, .15), q2*tt, 0);
//g = if (above(tt, .5), q3*tt, 0);
//b = if (above(tt, 0), q4*tt3, 0);

r = if (tt%q7, q2*tt, 0);
g = if (tt%q8, q3*tt, 0);
b = if (tt%q9, q4*tt, 0);
